# RUN_PARMS: scalebar_3857_geodesic.png [MAP2IMG] -m [MAPFILE] -i png -o [RESULT]
#
# Test local geodesic scalebar measurement in EPSG:3857.
#
# REQUIRES: OUTPUT=PNG
#
MAP

EXTENT -1000000 7899737 1000000 8899737
SIZE 220 80
UNITS METERS
IMAGECOLOR 255 255 255
FONTSET "../misc/fonts.lst"
IMAGETYPE png

PROJECTION
  "init=epsg:3857"
END

SCALEBAR
  MEASURE GEODESIC
  TRANSPARENT OFF
  LABEL
    COLOR 0 0 0
    SIZE 9
    TYPE TRUETYPE
    FONT "default"
  END
  SIZE 180 4
  COLOR 0 0 0
  BACKGROUNDCOLOR 255 255 255
  OUTLINECOLOR 0 0 0
  UNITS KILOMETERS
  INTERVALS 4
  STATUS EMBED
END

END
